CREATE DATABASE IF NOT EXISTS mydb;
USE mydb;
CREATE TABLE IF NOT EXISTS plaid_transactions (id BIGINT PRIMARY KEY AUTO_INCREMENT,transaction_id VARCHAR(128) UNIQUE,account_id VARCHAR(128),amount DECIMAL(14,2),iso_currency_code VARCHAR(16),unofficial_currency_code VARCHAR(16),category_primary VARCHAR(128),category_detailed VARCHAR(128),name VARCHAR(255),merchant_name VARCHAR(255),payment_channel VARCHAR(64),authorized_date DATE NULL,posted_date DATE NULL,pending BOOLEAN,raw_json JSON,loaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
